import { defineStore } from 'pinia'

export const usePaymentStatusStore = defineStore('payanddeliinfo', {
  state: () => ({
    paymentStatus:{
        payMethod:'',
        deliveryMethod:''
    }
  })
  ,
  actions: {
    setPaymentStatus(payMethod,deliveryMethod){
        this.paymentStatus.payMethod=payMethod
        this.paymentStatus.deliveryMethod=deliveryMethod
    }
    
  },
})