<template>
    <div class="container animate__animated animate__fadeInRight ">
        <div class="row">
            <div class="col-12 col-md-12 ">
                <div class="card  mt-4 rounded-3 p-3 m-3  ">
                    <div class="table-responsive-md">
                        <table class="table align-middle text-center ">
                            <thead>
                                <tr>
                                    <th  class="text-start my-auto " colspan="5"><h4>購物車內容({{ cartItemsCount }})</h4></th>
                                </tr>
                                <tr class="d-none d-md-table-row text-start">
                                    <th colspan="2">商品資料</th>
                                    <th>單件價格</th>
                                    <th>數量</th>
                                    <th>小計</th>
                                    <th>刪除</th>
                                </tr>
                            </thead>
                            <tbody> 
                                    <tr>
                                        <td v-if="isEmpty" colspan="5" class="text-center">
                                            購物車內沒有商品，快去前往購物吧～
                                        </td>
                                    </tr>          
                                    <tr  v-for="item in items" :key="item.id" class="text-start">
                                        <td class="w-25 h-25">
                                        <img class="img-fluid w-100 h-100" :src="item.productImg"  style="min-width: 60px; min-height: 60px;">
                                        </td>
                                        <td>
                                            {{ item.productName }}
                                        </td>
                                        <td>{{ item.productPrice }}</td>
                                        <td>
                                            <div class="btn-group" role="group" aria-label="Basic example">
                                                <button type="button" @click="minus(item.id)" class="btn btn-secondary btn-sm">-</button>
                                                <button type="button" disabled class="btn btn-white">{{item.quantity}}</button>
                                                <button type="button" @click="plus(item.id)" class="btn btn-secondary btn-sm">+</button>
                                            </div>
                                        </td>
                                        <td>{{ item.productPrice * item.quantity }}</td>
                                        <td>
                                            <button @click="deleteItem(item.id)" type="button" class="btn-close mw-25" aria-label="Close"></button>
                                        </td>
                                    </tr>                            
                            </tbody>
                        </table>
                    </div>
                    <router-link to="/products/category/all">
                        <div class="text-end mr-5"><h5>繼續購物</h5></div>
                    </router-link>
                </div>    
            </div>
        </div>
        <div class="row p-3 ">
            <div class="col-12 col-md-8">
                <div class="card p-1">
                    <table class="table">
                        <thead>
                            <tr >
                                <th >選擇送貨及付款方式</th>
                            </tr>
                        </thead>
                    </table>
                    <div class="m-3">
                        <div class="mb-3">
                            <h4 class="mb-3">選擇送貨方式</h4>
                            <select v-model="deliveryMethod" class="form-select" aria-label="deliverytype">
                                <option selected>宅配</option>
                                <option value="超商取貨">超商取貨</option>
                            </select>
                        </div>
                        <div class="mb-3">
                            <h4 class="mb-3">選擇付款方式</h4>
                            <select v-model="payMethod" class="form-select" aria-label="paytype">
                                <option value="貨到付款" selected>貨到付款</option>
                                <option value="信用卡支付">信用卡支付</option>
                                <option value="超商取貨">超商取貨</option>
                            </select>
                        </div> 
                    </div>
                </div>
            </div>
            <div class="col-12 col-md-4 mt-md-0 mt-3">
                <div class="card p-1">
                    <table class="table">
                        <thead>
                            <tr>
                                <th>訂單資訊</th>
                            </tr>
                        </thead>   
                        <tbody>
                            <tr>
                                <td colspan="2">
                                    合計：{{ totalPrice }}
                                </td>
                            </tr>
                            <tr>
                                <td colspan="2">
                                    <button   id="checkoutBtn" @click="goCheckOut" class="btn btn-success w-100">前往結賬</button>
                                </td>
                            </tr>
                            
                        </tbody>                 
                    </table>  
                </div>
            </div>
        </div>
    </div>

    <!-- 數量調整警告用 -->
    <div class="position-fixed bottom-0 end-0 p-3">
        <div id="alerttoast" class="toast" role="alert" aria-live="assertive" aria-atomic="true">
            <div class="toast-header">
            <strong class="me-auto">警告</strong>
            <button type="button" class="btn-close" data-bs-dismiss="toast" aria-label="Close"></button>
            </div>
            <div class="toast-body">
               商品數量不能低於1個!
            </div>
        </div>
    </div>


</template>

<script>
import {reactive, toRefs,toRaw,computed,ref} from 'vue'
import bootstrap from '../../node_modules/bootstrap/dist/js/bootstrap.js'
import {usePaymentStatusStore} from '@/store/paymentStatus'
import { useCartItemsStore } from '@/store/cartItems'
export default {
 name:'OrderConfirm',
 setup(){
    let cartItemsStore=useCartItemsStore()
    let payMethod=ref('貨到付款')
    let deliveryMethod=ref('宅配')
    let cartItems =reactive(JSON.parse(localStorage.getItem('cart')))
    let isEmpty=computed(()=>{
        return !cartItems.items.length
    })

    

    let totalPrice =computed(()=>{
        let temp=0
        for(var i=0;i<cartItems.items.length;i++){
            temp+=cartItems.items[i].quantity * cartItems.items[i].productPrice
        }
        return temp
    })

    let cartItemsCount=computed(()=>{
        return cartItems.items.length
    })

    function deleteItem(id){
        for(var i =0;i<cartItems.items.length;i++){
            if(cartItems.items[i].id===id){
                cartItems.items.splice(i,1)
            }
        }
        localStorage.setItem('cart',JSON.stringify(cartItems))
        cartItemsStore.cartTrigger()

        
    }

    function plus(id){
        for(var i =0;i<cartItems.items.length;i++){
            if(cartItems.items[i].id=== id){
                cartItems.items[i].quantity++
                localStorage.setItem('cart',JSON.stringify(toRaw(cartItems)))
            }
        }
    }

    function minus(id){
        for(var i =0;i<cartItems.items.length;i++){
            if(cartItems.items[i].id=== id){
                if(cartItems.items[i].quantity===1){
                    var element = new bootstrap.Toast(document.getElementById('alerttoast'))
                    element.show()
                }else{
                    cartItems.items[i].quantity--
                    localStorage.setItem('cart',JSON.stringify(toRaw(cartItems)))
                }
            }
        }
    }

    

    return{
        ...toRefs(cartItems),
        deleteItem,
        plus,
        minus,
        isEmpty,
        cartItemsCount,
        totalPrice,
        deliveryMethod,
        payMethod
    }
 },
 methods:{
    goCheckOut(){
        if(this.cartItemsCount ===0 ){
            const checkoutButton = document.getElementById('checkoutBtn')
            checkoutButton.className='btn btn-danger w-100 animate__animated animate__tada'
            setTimeout(() => {
                checkoutButton.className='btn btn-danger w-100 '
            }, 1000);
            checkoutButton.innerText='購物車內沒有商品'
            return   
        }

        usePaymentStatusStore().setPaymentStatus(this.payMethod,this.deliveryMethod)

        this.$router.push({
            name:'checkout',
        })
    }
 }
}

</script>

